import sys
input = sys.stdin.readline

def solve():
    MOD = 998244353
    n = int(input())
    a = list(map(int, input().split()))

    dp = {}  # dp[m] = count of subsequences with MEX = m

    for v in a:
        # Order matters - compute updates carefully
        new_contributions = {}

        # m = v+1: can add v = m-1, dp[v+1] *= 2
        if v+1 in dp:
            new_contributions[v+1] = new_contributions.get(v+1, dp.get(v+1, 0)) 
            dp[v+1] = dp[v+1] * 2 % MOD

        # m = v: can add v = m, dp[v+1] += dp[v]
        if v in dp:
            dp[v+1] = (dp.get(v+1, 0) + dp[v]) % MOD
            # dp[v] unchanged (we don't add v=m to keep MEX=v)

        # m = v-1: can add v = m+1, dp[v-1] *= 2
        if v-1 >= 0 and v-1 in dp:
            dp[v-1] = dp[v-1] * 2 % MOD

        # New subsequence starting with v
        if v == 0:
            dp[1] = (dp.get(1, 0) + 1) % MOD
        elif v == 1:
            dp[0] = (dp.get(0, 0) + 1) % MOD

    print(sum(dp.values()) % MOD)

t = int(input())
for _ in range(t):
    solve()

